// Build Claude API request body — TRIMMED to avoid rate limits
const webhookBody = $input.first().json.body;
const testResults = webhookBody.test_results || [];

// Trim: full detail for failed/skipped, name+suite only for passed
const trimmed = testResults.map(suite => {
  const failed = (suite.tests || []).filter(t => t.status !== 'passed');
  const passed = (suite.tests || []).filter(t => t.status === 'passed');
  return {
    source: suite.source,
    summary: suite.summary,
    failed_tests: failed,
    passed_sample: passed.slice(0, 20).map(t => ({ name: t.name, suite: t.suite })),
    total_passed_not_shown: Math.max(0, passed.length - 20)
  };
});

const systemPrompt = `You are a software testing analyst. Analyse Jest results and return ONLY valid JSON - no markdown, no preamble - matching this schema exactly:
{"run_summary":{"total_tests":0,"passed":0,"failed":0,"skipped":0,"duration_ms":0,"overall_health":"healthy|degraded|critical","health_reason":"string"},"failed_tests":[{"name":"string","suite":"string","failure_type":"assertion_error|timeout|import_error|setup_teardown|unexpected_exception|unknown","error_message":"string","fix_hint":"string"}],"brittle_tests":[{"name":"string","suite":"string","reason":"string","recommendation":"string"}],"anti_patterns":[{"suite":"string","pattern":"string","details":"string"}],"flaky_tests":[],"suggested_new_test":{"test_name":"string","target_suite":"string","what_to_assert":"string","rationale":"string"},"top_priority_fixes":["string"]}`;

const userMessage = `Analyse these test results (branch: ${webhookBody.branch}, actor: ${webhookBody.actor}):\n\n${JSON.stringify(trimmed)}`;

const claudeBody = {
  model: 'claude-opus-4-5',
  max_tokens: 2048,
  system: systemPrompt,
  messages: [{ role: 'user', content: userMessage }]
};

return [{ json: { claudeBody: JSON.stringify(claudeBody), webhookBody } }];

const claudeResponse = $input.first().json;
const rawText = claudeResponse.content[0].text.trim();
let analysis;
try {
  const cleaned = rawText.replace(/^```[\w]*\n?/, '').replace(/\n?```$/, '').trim();
  analysis = JSON.parse(cleaned);
} catch(e) {
  throw new Error(`Claude returned invalid JSON: ${rawText.substring(0, 300)}`);
}

const s = analysis.run_summary;
const webhookBody = $('Build Claude Payload').first().json.webhookBody;
const healthEmoji = s.overall_health === 'healthy' ? '✅' : s.overall_health === 'degraded' ? '⚠️' : '🔴';

let comment = `## ${healthEmoji} AI Test Analysis — ${s.overall_health.toUpperCase()}\n\n`;
comment += `> ${s.health_reason}\n\n`;
comment += `| Metric | Value |\n|--------|-------|\n`;
comment += `| Total Tests | ${s.total_tests} |\n| ✅ Passed | ${s.passed} |\n| ❌ Failed | ${s.failed} |\n| ⏭ Skipped | ${s.skipped} |\n\n`;

if (analysis.failed_tests && analysis.failed_tests.length > 0) {
  comment += `### ❌ Failed Tests\n\n`;
  for (const t of analysis.failed_tests) {
    comment += `**${t.name}** (\`${t.suite}\`)\n- Type: \`${t.failure_type}\` | Error: ${t.error_message}\n- 💡 ${t.fix_hint}\n\n`;
  }
}

if (analysis.brittle_tests && analysis.brittle_tests.length > 0) {
  comment += `### ⚠️ Brittle Tests\n\n`;
  for (const t of analysis.brittle_tests) {
    comment += `- **${t.name}** — ${t.reason}\n`;
  }
  comment += '\n';
}

if (analysis.top_priority_fixes && analysis.top_priority_fixes.length > 0) {
  comment += `### 🎯 Top Priority Fixes\n\n`;
  analysis.top_priority_fixes.forEach((fix, i) => { comment += `${i+1}. ${fix}\n`; });
  comment += '\n';
}

if (analysis.suggested_new_test && analysis.suggested_new_test.test_name) {
  const sug = analysis.suggested_new_test;
  comment += `### 💡 Suggested New Test\n**${sug.test_name}** — ${sug.what_to_assert}\n\n`;
}

comment += `---\n*Powered by Claude AI · [View CI run](https://github.com/${webhookBody.repo}/actions/runs/${webhookBody.run_id})*`;

return [{
  json: {
    ...webhookBody,
    analysis,
    pr_comment: comment,
    has_pr: !!(webhookBody.pr_number && webhookBody.pr_number !== '' && webhookBody.pr_number !== 'undefined')
  }
}];
